mapper.select:
SELECT id, sample_at, variable_name, numeric_value, raw_value,
       metric_kind_code, room_canonical, bundle_code,
       schema_version, ingest_batch_id, ext_json
FROM telemetry_value_archive
WHERE variable_name = #{variableName}

    AND sample_at >= #{from}


    AND sample_at <= #{to}

ORDER BY sample_at ASC, id ASC
